#include <stdio.h>
#include <math.h>

int main(void){
    int minuto=0,hora=0;
    char txt[5]={'0','0','0','0','0'}; //Inicializacion de la cadena que guarda el modelo HH:MM
    scanf("%s",&txt);//Carga de la hora en formato HH:MM
    getchar();
    fflush (stdin);
    hora=(txt[0]-'0')*10; //En la variable 'hora' se carga la decena de la hora introducida
    hora=hora+txt[1]-'0'; //Se carga la unidad de la hora en la variable 'hora' y se le suma a la decena extraida en la linea 10
    minuto=(txt[3]-'0')*10; //En la variable 'minuto' se carga la decena del minuto introducido
    minuto=minuto+txt[4]-'0'; //Se carga la unidad del minuto en la variable 'minuto' y se le suma a la decena extraida en la linea 12
    minuto++; //Aumentamos el minuto en uno por si se introdujo un hora capicua
   while(minuto>0)
    {
        if(minuto==60)//Si el minuto es 60 entonces agregamos sumamos 1 a hora y minuto vuelve a 0
        {
            minuto=0;
            hora++;
            if(hora==24) //Si hora es 24 se reinicia el reloj a la hora 00
            {
                hora=0;
            }
        }
        txt[0]=floor(hora/10)+'0';
        txt[1]=hora%10+'0';
        txt[3]=floor(minuto/10)+'0';
        txt[4]=minuto%10+'0';
        if(txt[0]==txt[4] && txt[1]==txt[3])
        {
            printf("%s",txt);
            break;
        }
        minuto++; //Contador de minuto
    }
}

