use std::io::stdin;
fn main() {
    let (mut h, m) = parse();
    let e = h;
    while reverse_number(h) > 59 || (reverse_number(h) <= m && h == e) {
        h += 1;
    }

    if h >= 24 {
        println!("00:00")
    } else {
        print_it(h, reverse_number(h));
    }
}

fn parse() -> (usize, usize) {
    let mut entry = String::new();
    let mut hours = String::new();
    let mut minutes = String::new();
    let mut b = false;
    stdin().read_line(&mut entry).unwrap();

    for i in entry.trim().chars() {
        if i == ':' {
            b = true;
        } else if b {
            minutes.push(i);
        } else {
            hours.push(i);
        };
    }
    (hours.parse().unwrap(), minutes.parse().unwrap())
}

fn reverse_number(val: usize) -> usize {
    ((val % 10) * 10) + ((val - (val % 10)) / 10)
}

fn print_it(a: usize, b: usize) {
    let hours: String;
    let minutes: String;

    if a < 10 {
        hours = format!("0{}", a);
    } else {
        hours = format!("{}", a);
    };
    if b < 10 {
        minutes = format!("0{}", b);
    } else {
        minutes = format!("{}", b);
    };
    println!("{}:{}", hours, minutes);
}
